<template>
  <v-container fluid fill-height align-start ma-0 pa-2>
    <v-row no-gutters>
      <i-page-title title="사용자 관리" />
      <v-layout row>
        <v-col cols="12" sm="12" lg="12" class="pa-2 pb-0">
          <i-card-top
            class="d-flex"
            :useBtnList="buttonUseList"
            @btnAdd="btnAdd()"
            @btnSearch="btnSearch()"
            @btnSave="btnSave()"
            @btnDelete="btnDelete()"
          >
            <template v-slot:body>
              <v-layout overflow-auto>
                <v-row no-gutters class="pa-2">
                  <v-col cols="12" md="3">
                    <v-select
                      v-model="vModelCompId"
                      :menu-props="{ offsetY: true }"
                      color="primary"
                      class="required mx-1"
                      item-text="compNm"
                      item-value="compId"
                      :items="compIdList"
                      placeholder="사업장"
                      dense
                      outlined
                      clearable
                    >
                    </v-select>
                  </v-col>
                </v-row>
              </v-layout>
            </template>
          </i-card-top>
        </v-col>
        <v-col cols="12" sm="12" lg="12" class="pa-2 pt-0">
          <i-card-vertical headerTitle="사용자 관리" device="web">
            <template v-slot:body>
              <v-layout column overflow-auto>
                <v-col cols="12" md="12" class="row pa-0">
                  <v-col cols="12" class="pa-0">
                    <DxDataGrid
                      id="userDataGrid"
                      width="100%"
                      class="layout-col-height00"
                      :ref="dxDataGridRef"
                      :data-source="gridMain"
                      :remote-operations="false"
                      :hover-state-enabled="true"
                      :allow-column-resizing="true"
                      :allow-column-reordering="true"
                      :row-alternation-enabled="true"
                      :column-auto-width="false"
                      :show-borders="true"
                      :show-row-lines="true"
                      key-expr="id"
                      :focused-row-enabled="true"
                      @editing-start="onEditingStart"
                      @editor-preparing="
                        e => {
                          onEditorPreparing(e)
                          detailOnEditorPreparing(e)
                        }
                      "
                      @focused-row-changed="handleFocusedRow"
                    >
                      <DxEditing mode="batch" :allow-updating="true" :select-text-on-edit-start="true" />

                      <DxSelection :select-all-mode="allMode" show-check-boxes-mode="always" mode="multiple" />

                      <DxColumn
                        data-field="userCd"
                        data-type="string"
                        width="120px"
                        alignment="left"
                        caption="아이디"
                        css-class="devest-grid-header-require"
                        header-cell-template="userCdHeader"
                      />
                      <template #userCdHeader>
                        <span>
                          아이디
                          <v-tooltip top>
                            <template v-slot:activator="{ on, attrs }">
                              <v-icon small v-bind="attrs" v-on="on" class="mx-1">
                                mdi-help-circle
                              </v-icon>
                            </template>
                            <span>
                              앞에 사업자ID는 저장 시 자동으로 생성됩니다.
                            </span>
                          </v-tooltip>
                        </span>
                      </template>

                      <DxColumn
                        data-field="userNm"
                        data-type="string"
                        width="120px"
                        alignment="left"
                        caption="사용자 명"
                        css-class="devest-grid-header-require"
                      />

                      <DxColumn
                        data-field="esgHrNo"
                        data-type="string"
                        width="100px"
                        alignment="left"
                        caption="인원연결"
                        edit-cell-template="checkNoEditor"
                      >
                        <DxLookup :data-source="esgHrNoListLookup" value-expr="esgHrNo" display-expr="checkTargetNm" />
                      </DxColumn>

                      <template #checkNoEditor="{ data: cellInfo }">
                        <DevLookup
                          :data-source="dataSource(cellInfo)"
                          :value="cellInfo.value"
                          placeholder=""
                          :grouped="true"
                          value-expr="esgHrNo"
                          display-expr="displayCheckNm"
                          :showClearButton="true"
                          @value-changed="onHrValueChanged($event, cellInfo)"
                        >
                          <DxDropDownOptions width="250px" :title="$t('chooseThePeople')" :close-on-outside-click="true" />
                        </DevLookup>
                      </template>

                      <DxColumn
                        data-field="userPs"
                        data-type="string"
                        width="80px"
                        alignment="left"
                        caption="패스워드"
                        :calculate-display-value="getUserPsHide"
                        css-class="devest-grid-header-require"
                      />
                      <DxColumn
                        data-field="userPsCheck"
                        data-type="string"
                        width="90px"
                        alignment="left"
                        caption="패스워드확인"
                        :calculate-display-value="getUserPsCheckHide"
                        css-class="devest-grid-header-require"
                      />
                      <DxColumn
                        data-field="psChked"
                        data-type="boolean"
                        width="80px"
                        alignment="center"
                        caption="패스워드변경"
                        edit-cell-template="checkBoxEditor"
                        true-text="허용"
                        false-text="미허용"
                      />

                      <DxColumn
                        data-field="grpAuthCd"
                        data-type="string"
                        width="100px"
                        alignment="center"
                        caption="권한그룹"
                        css-class="devest-grid-header-require"
                      >
                        <DxLookup :data-source="selectList" value-expr="grpAuthCd" display-expr="grpAuthNm" />
                      </DxColumn>

                      <DxColumn
                        data-field="groupId"
                        data-type="string"
                        width="140px"
                        alignment="center"
                        caption="사업장(그룹)"
                        :allow-editing="false"
                        css-class="devest-grid-header-require"
                        header-cell-template="groupHeader"
                      >
                        <DxLookup :data-source="compIdList" value-expr="compId" display-expr="compNm" />
                      </DxColumn>
                      <template #groupHeader>
                        <span>
                          사업장(그룹)
                          <v-tooltip top>
                            <template v-slot:activator="{ on, attrs }">
                              <v-icon small v-bind="attrs" v-on="on" class="mx-1">
                                mdi-help-circle
                              </v-icon>
                            </template>
                            <span>
                              사업장 선택 시 자동으로 지정됩니다.
                            </span>
                          </v-tooltip>
                        </span>
                      </template>
                      <DxColumn
                        data-field="compId"
                        data-type="string"
                        width="140px"
                        alignment="center"
                        caption="사업장"
                        css-class="devest-grid-header-require"
                        edit-cell-template="comp-selector"
                      >
                        <DxLookup :data-source="compIdList" value-expr="compId" display-expr="compNm" />
                      </DxColumn>

                      <template #comp-selector="{ data : cellInfo}">
                        <DevLookup
                          :v-model="cellInfo.data.compId"
                          :data-source="compIdList"
                          value-expr="compId"
                          display-expr="compNm"
                          class="mx-1"
                          @value-changed="onCompValueChanged($event, cellInfo)"
                        >
                        </DevLookup>
                      </template>

                      <!--<DxColumn data-field="empNo" data-type="string" width="80px" alignment="left" caption="사번" />-->
                      <!--<DxColumn data-field="hpNo" data-type="string" width="120px" alignment="left" caption="휴대전화번호" />-->
                      <DxColumn
                        data-field="userStatus"
                        data-type="string"
                        width="60px"
                        alignment="center"
                        caption="상태"
                        css-class="devest-grid-header-require"
                      >
                        <DxLookup :data-source="userStatusList" value-expr="minorCd" display-expr="minorNm" />
                      </DxColumn>

                      <DxColumn
                        data-field="useYn"
                        data-type="boolean"
                        width="50px"
                        alignment="center"
                        caption="사용"
                        edit-cell-template="checkBoxEditor"
                        true-text="사용"
                        false-text="미사용"
                      />

                      <DxColumn
                        data-field="connStartDt"
                        data-type="date"
                        width="150px"
                        format="yyyy.MM.dd"
                        alignment="center"
                        caption="접속허용 시작일"
                        edit-cell-template="dateEditor"
                        css-class="devest-grid-header-require"
                      />

                      <DxColumn
                        data-field="connEndDt"
                        data-type="date"
                        width="150px"
                        format="yyyy.MM.dd"
                        alignment="center"
                        caption="접속허용 종료일"
                        edit-cell-template="dateEditor"
                        css-class="devest-grid-header-require"
                      />
                      <template #dateEditor="{ data: cellInfo }">
                        <div>
                          <DxDateBox
                            :value="cellInfo.value"
                            type="date"
                            picker-type="calendar"
                            display-format="yyyy.MM.dd"
                            :use-mask-behavior="true"
                            @value-changed="onDateValueChanged($event, cellInfo)"
                          />
                        </div>
                      </template>

                      <DxColumn
                        data-field="enableAlarmAllYn"
                        data-type="boolean"
                        width="200px"
                        alignment="center"
                        caption="전체알람수신 동의여부"
                        edit-cell-template="checkBoxEditor"
                        all-text="전체"
                        true-text="동의"
                        false-text="미동의"
                      />

                      <DxColumn
                        data-field="enableAlarmEduYn"
                        data-type="boolean"
                        width="200px"
                        alignment="center"
                        caption="교육알람수신 동의여부"
                        :visible="false"
                        edit-cell-template="checkBoxEditor"
                      />

                      <DxColumn
                        data-field="enableAlarmHealthYn"
                        data-type="boolean"
                        width="200px"
                        alignment="center"
                        caption="건강알람수신 동의여부"
                        :visible="false"
                        edit-cell-template="checkBoxEditor"
                      />

                      <DxColumn
                        data-field="lastLoginOs"
                        data-type="string"
                        width="120px"
                        alignment="center"
                        caption="마지막 접속 OS"
                        :allow-editing="false"
                      />

                      <DxColumn data-field="email" data-type="string" width="150px" alignment="left" caption="이메일" />

                      <DxColumn data-field="hpNo" data-type="string" width="120px" alignment="left" caption="휴대전화번호" />

                      <DxColumn data-field="remark" data-type="string" alignment="left" caption="비고" />

                      <!-- <template #textBoxEdior="{ data: selectRows }">
                      <DxTextBox :mode="passwordMode" :value="selectRows.value" :onValueChanged="value => onValueChanged(value, selectRows)" />
                    </template> -->
                      <template #checkBoxEditor="{ data: cellInfo }">
                        <DxCheckBox :value="cellInfo.value == 'Y'" :onValueChanged="value => onCheckValueChanged(value, cellInfo)" />
                      </template>
                    </DxDataGrid>
                  </v-col>
                </v-col>
              </v-layout>
            </template>
          </i-card-vertical>
        </v-col>
      </v-layout>
    </v-row>
  </v-container>
</template>

<script>
import { DxDataGrid, DxColumn, DxLookup, DxEditing, DxSelection } from 'devextreme-vue/data-grid'
import { DxLookup as DevLookup, DxDropDownOptions } from 'devextreme-vue/lookup'
import DxCheckBox from 'devextreme-vue/check-box'
import iButtonList from '@/components/common/iButtonList.vue'
import iPageTitle from '@/components/common/iPageTitle.vue'
import iCardTop from '@/components/common/iCardTop.vue'
import iCardVertical from '@/components/common/iCardVertical.vue'
import { getUserListByCompId, getUserListInfo, getUserAuthList, saveUserList, deleteUserList, getDuplicateConfirms } from '@/api/system/userManage'
import { getGrpAuth, getCommonCode } from '@/api/common/commonApi'
import { getCompanyList } from '@/api/setting/compManage'
import notify from 'devextreme/ui/notify'
import { AesEncrypt, AesDecrypt } from '@/utils/aes256' //cyrptojs 적용(aes256)
import { DxTextBox } from 'devextreme-vue/text-box'
import { getHrJbrpApi } from '@/api/baseManage/esgHRManage'
import baseview from '@/views/base/baseview.vue' //20220414 LYJ base page 추가
import BaseDataGrid from '@/views/base/BaseDataGrid.vue'
import DxDateBox from 'devextreme-vue/date-box'
import { validEmail, validTell } from '@/utils/validate.js'

export default {
  mixins: [baseview, BaseDataGrid], //20220414 LYJ base page 추가
  name: 'userManage',
  components: {
    'i-card-vertical': iCardVertical,
    'i-card-top': iCardTop,
    'i-page-title': iPageTitle,
    iButtonList,
    DxDataGrid,
    DxColumn,
    DxCheckBox,
    DxLookup,
    DxEditing,
    DxSelection,
    DxTextBox,
    DxLookup,
    DevLookup,
    DxDropDownOptions,
    DxDateBox
  },
  data() {
    return {
      groupKey: '',
      dxDataGridRef: 'userDataGrid',
      gridMain: [],
      valid: true,
      buttonUseList: [
        'btnSearch', //조회
        'btnAdd', //추가
        'btnSave', //저장
        'btnDelete' //삭제
      ],
      allMode: 'allPages',
      grpAuthCd: '',
      // phonePattern: /^\d{3}-(\d{4}||\d{3})-\d{4}$/i,
      compIdList: [],
      userStatusList: [], //상태
      selectList: [], //사용자그룹권한
      focusData: [],
      esgHrNoList: [],
      esgHrNoListSource: [],
      esgHrNoListLookup: [],
      //패스워드 안보이게 처리
      passwordMode: 'password',
      vModelCompId: ''
    }
  },
  beforeMount() {
    Promise.all([getCommonCode('C0006'), getCompanyList(), getGrpAuth(), getHrJbrpApi({ compId: '' })]).then(response => {
      let failedResponse = response.find(element => !element.success)
      if (failedResponse == null) {
        //상태
        this.userStatusList = response[0].list.slice()
        //회사
        this.compIdList = response[1].list.slice()
        // this.vModelCompId = this.compIdList[0].compId
        //권한
        this.selectList = response[2].list.slice()

        this.esgHrNoList = []
        this.esgHrNoList = response[3].list.slice()
        var esgHrNoListSource = response[3].list.filter(element => element.key !== '기타' && element.key !== '전체')
        this.esgHrNoListLookup = esgHrNoListSource.reduce((acc, val) => acc.concat(val.items), [])
      } else {
        this.$vToastify.error({ body: failedResponse.msg })
        this.vToastify(failedResponse.msg, 'error')
      }
    })
  },
  mounted() {
    this.btnSearch()
  },
  methods: {
    onCompValueChanged(e, cellInfo) {
      cellInfo.setValue(e.value)
      cellInfo.component.selectRows(cellInfo.row.key, true)
      cellInfo.component.cellValue(cellInfo.row.rowIndex, 'groupId', e.value)
      cellInfo.component.closeEditCell()
    },
    dataSource(cellInfo) {
      let items = this.esgHrNoList[0].items.filter(element => element.compId == cellInfo.data.compId)
      let dataSource = [
        {
          items: items,
          key: '인원',
          sort: 0
        }
      ]
      return dataSource
    },
    async signIn() {
      return new Promise(async (resolve, reject) => {
        this.GetDataGrid(this.dxDataGridRef).saveEditData()
        var selectedRows = await this.GetDataGrid(this.dxDataGridRef).getSelectedRowsData()

        //cyrptojs 적용(aes256) 20220404 by lyj
        selectedRows.forEach(element => {
          element.userPs = AesEncrypt(element.userPs)
          element.userPsCheck = AesEncrypt(element.userPsCheck)
        })
        //decrption test
        resolve(true)
      })
    },
    // 패스워드 display ***처리
    getUserPsHide(rowData) {
      const psChked = rowData.psChked == 'N'
      return (rowData = psChked ? '********' : rowData.userPs)
    },
    // 패스워드 확인 display ***처리
    getUserPsCheckHide(rowData) {
      const psChked = rowData.psChked == 'N'
      return (rowData = psChked ? '********' : rowData.userPsCheck)
    },
    ///////////////////////////////////////
    /*       Toolbar Button Event        */
    ///////////////////////////////////////

    btnSearch() {
      this.gridInit(this.GetDataGrid(this.dxDataGridRef))
      this.openLoading('searching')

      getUserListByCompId({ compId: this.vModelCompId }, true)
        .then(response => {
          if (response.success) {
            this.gridInit(this.GetDataGrid(this.dxDataGridRef))
            this.gridMain = []
            this.gridMain = response.list
            this.FocusFirstRow(this.GetDataGrid(this.dxDataGridRef))
          }
        })
        .finally(() => {
          this.endLoading()
        })
    },
    btnAdd() {
      let newRow = {
        id:
          this.gridMain.filter(el => el.__created__).length > 0
            ? this.gridMain.filter(el => el.__created__).reduce((maxEl, el) => (el.id > maxEl.id ? el : maxEl)).id + 1
            : this.gridMain.length + 1,
        useYn: 'Y',
        psChked: 'Y',
        hpNo: '',
        groupId: this.groupKey,
        compId: this.groupKey,
        userStatus: 'W',
        enableAlarmAllYn: 'Y',
        enableAlarmEduYn: 'Y',
        enableAlarmHealthYn: 'Y'
      }
      Object.defineProperty(newRow, '__created__', { value: true, writable: true, enumerable: true, configurable: true })
      this.GetDataGrid(this.dxDataGridRef).newRow(newRow)
      this.GetDataGrid(this.dxDataGridRef).selectRows(newRow.id, true)
    },
    async btnSave() {
      //20220630 LYJ selectedRows 정의되지않아 에러남 추가함 start [[
      var selectedRows = await this.GetDataGrid(this.dxDataGridRef).getSelectedRowsData()
      if (selectedRows.length === 0) {
        this.vToastify(this.$t('selectionData'), 'warn')
        return
      }
      //20220630 LYJ selectedRows 정의되지않아 에러남 추가함 end ]]
      //패스워드 암호화 적용여부

      this.vToastifyPrompt(
        this.$t('doSaveData'),
        'info',
        async current => {
          this.GetDataGrid(this.dxDataGridRef).beginUpdate()
          this.GetDataGrid(this.dxDataGridRef).saveEditData()
          var pattern = /\s/g
          var index = selectedRows.findIndex(
            element =>
              element.userCd == null ||
              element.userNm == null ||
              element.compId == null ||
              element.useYn == null ||
              element.grpAuthCd == null ||
              element.userStatus == null ||
              (element.psChked == 'Y' && element.userPs == null && element.userPsCheck == null) ||
              element.userCd.trim() == '' ||
              element.userNm.trim() == '' ||
              element.compId.trim() == '' ||
              element.useYn.trim() == '' ||
              element.grpAuthCd.trim() == '' ||
              element.userStatus.trim() == '' ||
              element.userCd.match(pattern) != null
          )
          if (index >= 0) {
            this.vToastify(`${this.$t('msgReqValidate')}`, 'warn')
            this.GetDataGrid(this.dxDataGridRef).endUpdate()
            return
          }

          //패스워드 패스워드 확인 값비교
          let index2 = selectedRows.findIndex(element => element.userPs != element.userPsCheck)
          if (index2 >= 0) {
            this.vToastify(this.$t('패스워드와 패스워드확인이 일치하지 않습니다.'), 'warn')
            this.GetDataGrid(this.dxDataGridRef).endUpdate()
            return
          }

          //유효성 검사
          var valid = ''
          var patternIndex = selectedRows.findIndex(element => {
            if (!(element.email == '' || element.email == undefined || element.email == null) && !validEmail(element.email)) {
              valid = 'email'
              return true
            } else if (element.email && element.email.length > 50) {
              valid = 'email2'
              return true
            } else if (!(element.hpNo == '' || element.hpNo == undefined || element.hpNo == null) && !validTell(element.hpNo)) {
              valid = 'hpNo'
              return true
            }
          })
          if (patternIndex >= 0) {
            this.vToastify(valid == 'email' ? this.$t('올바르지 않은 이메일 형식입니다.') : this.$t(''), 'warn')
            this.vToastify(valid == 'email2' ? this.$t('이메일은 50자 이내로 입력하세요.') : this.$t(''), 'warn')
            this.vToastify(valid == 'hpNo' ? this.$t('올바르지 않은 휴대전화번호 형식입니다.') : this.$t(''), 'warn')
            this.GetDataGrid(this.dxDataGridRef).endUpdate()
            return
          }
          let userCdSet = new Set()
          let checkDuplilcateId = false
          let searchParams = []
          selectedRows.forEach(element => {
            //저장 시 comp_id 제외하고 저장해주세요.
            element.userCd = element.userCd.replace(element.compId + '_', '')
            if (element.createdAt == undefined) {
              searchParams.push({ userCd: element.compId + '_' + element.userCd })
            }
            if (userCdSet.has(element.compId + '_' + element.userCd)) {
              checkDuplilcateId = true
            } else {
              userCdSet.add(element.compId + '_' + element.userCd)
            }
            element.__created__ = true
          })
          getDuplicateConfirms(searchParams).then(async res => {
            if (res.list.length > 0 || checkDuplilcateId) {
              this.vToastify(this.$t('중복된 아이디가 있습니다.'), 'warn')
              this.GetDataGrid(this.dxDataGridRef).endUpdate()
              return
            } else {
              // 유효성검사가 끝난 비밀번호 암호화 처리
              if ({ psChked: 'Y' }) {
                await this.signIn()
              } else {
                this.psInit()
              }
              this.openLoading('saving')
              //저장 api
              saveUserList(selectedRows, true)
                .then(res => {
                  this.FocusFirstRow(this.GetDataGrid(this.dxDataGridRef))
                  this.btnSearch(false)
                })
                .finally(() => {
                  this.GetDataGrid(this.dxDataGridRef).endUpdate()
                  this.endLoading()
                })
            }
          })
        },
        null,
        true
      )
    },
    async btnDelete() {
      let selectedRows = await this.GetDataGrid(this.dxDataGridRef).getSelectedRowsData()
      if (selectedRows.length === 0) {
        this.vToastify(this.$t('selectionData'), 'warn')
        return
      }

      this.vToastifyPrompt(
        this.$t('doDeleteData'),
        'info',
        current => {
          this.GetDataGrid(this.dxDataGridRef).beginUpdate()
          this.GetDataGrid(this.dxDataGridRef).saveEditData()
          this.openLoading('deleting')
          //삭제 api
          const param = selectedRows.filter(el => !el.__created__)
          const newIds = selectedRows.filter(el => el.__created__).map(el => el.id)
          this.gridMain = this.gridMain.filter(el => !newIds.includes(el.id))
          const finishEvent = () => {
            this.GetDataGrid(this.dxDataGridRef).endUpdate()
            this.endLoading()
          }
          if (param.length !== 0) {
            deleteUserList(param, true)
              .then(() => {
                this.deleteCallBack(selectedRows)
                this.FocusFirstRow(this.GetDataGrid(this.dxDataGridRef))
              })
              .finally(() => finishEvent())
          } else {
            finishEvent()
          }
        },
        null,
        true
      )
    },
    ///////////////////////////////////////
    /*           DataGrid Event          */
    ///////////////////////////////////////
    // onValueChanged(e, selectRows){
    //   selectRows.setValue(e.value)
    // },
    handleCheckBoxFilter(value, operation, key) {
      return [key, operation, value ? 'Y' : 'N']
    },
    onHrValueChanged(e, cellInfo) {
      cellInfo.setValue(e.value)
      cellInfo.component.selectRows(cellInfo.row.key, true)
    },
    onCheckValueChanged(value, cellInfo) {
      cellInfo.setValue(cellInfo.value === 'Y' ? 'N' : 'Y')
      this.GetDataGrid(this.dxDataGridRef).saveEditData()
      this.GetDataGrid(this.dxDataGridRef).selectRows(cellInfo.row.key, true)
      cellInfo.component.updateDimensions()
    },
    detailOnEditorPreparing(e) {
      if (e.parentType == 'dataRow') {
        var valueChanged = this.onCellValueChanged
        e.editorOptions.onValueChanged = args => {
          if (e.index > -1) valueChanged(args.value, e)
        }
      }
    },
    onCellValueChanged(value, cellInfo) {
      cellInfo.setValue(value)
      this.GetDataGrid(this.dxDataGridRef).selectRows(cellInfo.row.key, true)
    },

    psInit() {
      var selectedRows = this.GetDataGrid(this.dxDataGridRef).getSelectedRowsData()
      selectedRows.forEach(element => {
        element.userPs = null
        element.userPsCheck = null
      })
    },
    ///////////////////////////////////////
    /*             etc Event             */
    ///////////////////////////////////////
    deleteCallBack(selectedRows) {
      var index = null
      selectedRows.forEach(key => {
        index = this.gridMain.findIndex(obj => obj == key)
        this.gridMain.splice(index, 1)
      })
    },
    //추가된 행이 아니면 수정 불가능하게 설정
    onEditingStart(e) {
      // if ((e.column.dataField == 'userCd' && !e.data.__created__) || (e.column.dataField == 'compId' && !e.data.__created__)) e.cancel = true
      if (e.column.dataField == 'userCd' && !e.data.__created__) e.cancel = true
      else e.cancel = false

      if ((e.column.dataField == 'userPs' && e.data.psChked != 'Y') || (e.column.dataField == 'userPsCheck' && e.data.psChked != 'Y')) e.cancel = true
    },
    //로우 포커스 이벤트
    handleFocusedRow(e) {
      if (e.row != undefined) {
        if (e.row.rowType === 'group') {
          this.groupKey = e.row.key[0]
        } else {
          this.groupKey = e.row.data.compId
        }
      }
    },
    onDateValueChanged(event, cellInfo) {
      //날짜 세팅
      const date = new Date(event.value)
      const year = date.getFullYear()
      const month = String(date.getMonth() + 1).padStart(2, '0')
      const day = String(date.getDate()).padStart(2, '0')
      const dateFormat = `${year}.${month}.${day}`
      //그리드 삽입
      const cell = cellInfo.data
      cell[cellInfo.column.dataField] = dateFormat
      cellInfo.setValue(dateFormat)
      this.$refs[this.dxDataGridRef].instance.selectRows(cellInfo.row.key, true)
    }
  }
}
</script>

